import { useState, useEffect, useCallback, useRef } from "react";

const useWidth = () => {
  const [w, setW] = useState(window.innerWidth);
  useEffect(() => {
    let t;
    const fn = () => { clearTimeout(t); t = setTimeout(() => { const nw = window.innerWidth; setW(p => Math.abs(p - nw) > 100 ? nw : p); }, 500); };
    window.addEventListener("resize", fn);
    return () => { window.removeEventListener("resize", fn); clearTimeout(t); };
  }, []);
  return w;
};

const MONTHLY = 1400;
const DAILY = MONTHLY / 30.4375;
const DEPOSIT = 700;

function calcPaymentSchedule(ci, co) {
  if (!ci || !co) return null;
  const d1 = new Date(ci + "T00:00:00"), d2 = new Date(co + "T00:00:00");
  if (d2 <= d1) return null;
  const totalDays = Math.round((d2 - d1) / 86400000);
  const fmt = d => d.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" });
  if (totalDays <= 45) {
    const totalEst = Math.round(totalDays * DAILY);
    return { totalDays, totalEst, isShort: true, dueToday: totalEst,
      schedule: [{ label: "Full stay — due at signing", date: fmt(d1), amount: totalEst, isFirst: true }] };
  }
  const schedule = [];
  const endOfFirst = new Date(d1.getFullYear(), d1.getMonth() + 1, 1);
  const firstDays = Math.round((endOfFirst - d1) / 86400000);
  const firstAmt = Math.round(firstDays * DAILY);
  const dueToday = DEPOSIT + firstAmt;
  schedule.push({ label: `$700 deposit + ${firstDays} days prorated (${fmt(d1)} – ${fmt(new Date(endOfFirst - 86400000))})`, date: "Due at signing", amount: dueToday, isFirst: true });
  let cursor = new Date(endOfFirst);
  while (true) {
    const next = new Date(cursor.getFullYear(), cursor.getMonth() + 1, 1);
    if (next >= d2) break;
    schedule.push({ label: `Full month — ${cursor.toLocaleDateString("en-US", { month: "long", year: "numeric" })}`, date: `${fmt(cursor)} (1st)`, amount: MONTHLY });
    cursor = next;
  }
  if (cursor < d2) {
    const lastDays = Math.round((d2 - cursor) / 86400000);
    if (lastDays > 0) schedule.push({ label: `${lastDays} days — ${cursor.toLocaleDateString("en-US", { month: "long", year: "numeric" })} (partial)`, date: `${fmt(cursor)} (1st)`, amount: Math.round(lastDays * DAILY), isLast: true });
  }
  const totalEst = schedule.reduce((s, p) => s + p.amount, 0);
  return { totalDays, totalEst, isShort: false, dueToday, deposit: DEPOSIT, firstDays, firstAmt, schedule };
}

function calcPrice(ci, co) {
  if (!ci || !co) return null;
  const d1 = new Date(ci + "T00:00:00"), d2 = new Date(co + "T00:00:00");
  if (d2 <= d1) return null;
  const days = Math.round((d2 - d1) / 86400000);
  return { days, total: Math.round(days * DAILY) };
}

