function ImgSlot({ url, label, height, radius = "8px" }) {
  const [err, setErr] = useState(false);
  if (url && !err) return <img src={url} alt={label} onError={() => setErr(true)} style={{ width: "100%", height, objectFit: "cover", borderRadius: radius, display: "block" }} />;
  return (
    <div style={{ width: "100%", height, borderRadius: radius, background: "#1a1410", border: "2px dashed #3a2e22", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: "4px" }}>
      <span style={{ fontSize: "20px" }}>📷</span>
      <span style={{ fontSize: "10px", fontWeight: "700", color: "#A89070", textAlign: "center", padding: "0 6px" }}>{label}</span>
    </div>
  );
}

function Gallery({ images, mainH = 200 }) {
  const [active, setActive] = useState(0);
  const n = images.length;
  const th = n > 6 ? 32 : 38;
  return (
    <div>
      <ImgSlot url={images[active]?.url} label={images[active]?.label} height={mainH} radius="12px 12px 0 0" />
      {n > 1 && (
        <div style={{ display: "flex", gap: "2px", padding: "2px", background: "#080604", borderRadius: "0 0 12px 12px" }}>
          {images.map((img, i) => (
            <div key={i} onClick={() => setActive(i)} style={{ flex: 1, cursor: "pointer", borderRadius: "4px", overflow: "hidden", border: i === active ? "2px solid #C8944A" : "2px solid transparent", transition: "border 0.15s" }}>
              <ImgSlot url={img.url} label={img.label} height={th} radius="2px" />
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

